from collections import Counter

class Solution(object):
    def maximumLength(self, nums):
        freq = Counter(nums)
        ans = 1
        # Handle x = 1 separately: can use any odd count of 1s
        if freq[1] > 0:
            ans = freq[1] if freq[1] % 2 == 1 else freq[1] - 1
        # For each x > 1, try building chain x, x^2, x^4, ...
        for x in freq:
            if x == 1:
                continue
            length = 0
            cur = x
            while cur in freq and freq[cur] >= 2:
                length += 2
                cur = cur * cur
            # Add center element if cur exists at least once
            if cur in freq and freq[cur] >= 1:
                length += 1
            ans = max(ans, length)
        return ans
